def cc(x1, y1, x2, y2):
    xd = x2 - x1
    yd = y2 - y1
    xc = (x1 + x2) / 2
    yc = (y1 + y2) / 2
    k = pow(1.0 / (xd**2 + yd**2) - 0.25, 0.5)
    xd *= k
    yd *= k
    return [[xc - yd, yc + xd], [xc + yd, yc - xd]]

