def d4(x,y):
  ret = 0
  while x > y:
    y *= 4
    ret += 1
  return ret
def cost(ls):
  l = len(ls)
  ret = [0]*l
  stack = [(l-1,10**18)]
  for i in range(l-1)[::-1]:
    ret[i] = ret[i+1]
    if ls[i] <= ls[i+1]:
      d = d4(ls[i+1],ls[i])-1
      if d > 0:
        stack.append((i,d))
    else:
      d = d4(ls[i],ls[i+1])
      while d:
        idx,num = stack.pop()
        if d > num:
          ret[i] += (idx-i)*num
          d -= num
        else:
          ret[i] += (idx-i)*d
          num -= d
          d = 0
          if num:
            stack.append((idx,num))
  return ret
