import sys

def parse_int(s: str) -> int:
    s = s.strip()
    if not s:
        return 0
    return int(s)

def count_upto(n: int, m: int) -> int:
    if n <= 0:
        return 0
    digits = list(map(int, str(n)))
    L = len(digits)

    # dp[pos][tight][started][last_digit][dir]
    # dir: 0 = undefined (no previous comparison yet), 1 = last move was up, 2 = last move was down
    # last_digit valid only if started
    from functools import lru_cache

    @lru_cache(None)
    def dfs(pos, tight, started, last, dir_):
        if pos == L:
            return 1 if started else 0
        limit = digits[pos] if tight else 9
        res = 0
        for d in range(limit + 1):
            ntight = tight and (d == limit)
            if not started and d == 0:
                res += dfs(pos + 1, ntight, 0, 0, 0)
            elif not started:
                res += dfs(pos + 1, ntight, 1, d, 0)
            else:
                if d == last:
                    continue
                if dir_ == 0:
                    ndir = 1 if d > last else 2
                    res += dfs(pos + 1, ntight, 1, d, ndir)
                elif dir_ == 1:
                    if d < last:
                        res += dfs(pos + 1, ntight, 1, d, 2)
                else:
                    if d > last:
                        res += dfs(pos + 1, ntight, 1, d, 1)
        return res

    total = dfs(0, 1, 0, 0, 0)

    # Exclude 0 if counted (it isn't), and numbers not divisible by m handled separately below.
    # Need divisibility by m, so use a different DP.
    return total

def count_zigzag_div_upto(n: int, m: int) -> int:
    if n <= 0:
        return 0
    digits = list(map(int, str(n)))
    L = len(digits)

    from functools import lru_cache

    @lru_cache(None)
    def dfs(pos, tight, started, last, dir_, rem):
        if pos == L:
            return 1 if started and rem == 0 else 0
        limit = digits[pos] if tight else 9
        res = 0
        for d in range(limit + 1):
            ntight = tight and (d == limit)
            if not started and d == 0:
                res += dfs(pos + 1, ntight, 0, 0, 0, 0)
            elif not started:
                res += dfs(pos + 1, ntight, 1, d, 0, d % m)
            else:
                if d == last:
                    continue
                if dir_ == 0:
                    ndir = 1 if d > last else 2
                    res += dfs(pos + 1, ntight, 1, d, ndir, (rem * 10 + d) % m)
                elif dir_ == 1:
                    if d < last:
                        res += dfs(pos + 1, ntight, 1, d, 2, (rem * 10 + d) % m)
                else:
                    if d > last:
                        res += dfs(pos + 1, ntight, 1, d, 1, (rem * 10 + d) % m)
        return res

    return dfs(0, 1, 0, 0, 0, 0)

def main():
    data = sys.stdin.read().strip().split()
    if len(data) < 3:
        return
    A = parse_int(data[0])
    B = parse_int(data[1])
    M = parse_int(data[2])

    ans = count_zigzag_div_upto(B, M) - count_zigzag_div_upto(A - 1, M)
    print(ans % 10000)

